delete
from W_EMPLOYEE_DS
where rowid in (select dup_rowid from
(
select a.rowid dup_rowid,
RANK() over (partition by a.INTEGRATION_ID, a.DATASOURCE_NUM_ID ,a.SRC_EFF_FROM_DT
order by a.rowid ASC
) row_rank
from W_EMPLOYEE_DS a,
(
select INTEGRATION_ID
,DATASOURCE_NUM_ID ,SRC_EFF_FROM_DT
from W_EMPLOYEE_DS  group by INTEGRATION_ID, 
DATASOURCE_NUM_ID,SRC_EFF_FROM_DT having count(1) > 1
) b
where a.INTEGRATION_ID = b.INTEGRATION_ID
and a.DATASOURCE_NUM_ID = b.DATASOURCE_NUM_ID
and a.SRC_EFF_FROM_DT = b.SRC_EFF_FROM_DT
) where row_rank > 1);

commit;


